INSERT INTO match_results (match_id, player_id, points, ups, partner_id) SELECT m.id, (SELECT id FROM players WHERE name='Kim Damsgaard'), 2, 4, (SELECT id FROM players WHERE name='Lasse Jakobsen') FROM matches m JOIN rounds r ON r.id=m.round_id JOIN tournaments t ON t.id=r.tournament_id WHERE t.year=2024 AND r.round_number=1 AND m.match_number=1 ON DUPLICATE KEY UPDATE points=VALUES(points), ups=VALUES(ups), partner_id=VALUES(partner_id);
